		Harness:     "claude",
		BillingMode: "paid",
		StartedAt:   now,
		ToolCalls: []agent.ToolCallEntry{
			{Tool: "Read", Input: `{"path":"a"}`, Output: "ok", Duration: 12},
			{Tool: "Bash", Input: `{"cmd":"ls"}`, Error: "exit 1"},
